#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use DBI;

my $cgi = CGI->new();
my $username = $cgi->param('username') || '';
my $password = $cgi->param('password') || '';

print $cgi->header('text/html');

# Secure implementation with parameterized queries
my $dbh = DBI->connect("dbi:mysql:database=authdb;host=localhost", "user", "pass", { RaiseError => 1, AutoCommit => 1 });

# Use parameterized query to prevent SQL injection
my $sql = "SELECT * FROM users WHERE username=? AND password=?";
my $sth = $dbh->prepare($sql);
$sth->execute($username, $password);

if (my $row = $sth->fetchrow_hashref()) {
    print "<h2>Login Successful</h2>";
    print "<p>Welcome, $username!</p>";
} else {
    print "<h2>Login Failed</h2>";
    print "<p>Invalid username or password.</p>";
}

$sth->finish();
$dbh->disconnect();